function update_ui(logged){let els=Array.from(document.getElementsByClassName("l"));logged?(els.forEach(e=>{e.classList.remove("is-hidden")}),document.getElementById("anonymous").classList.add("is-hidden")):(els.forEach(e=>{e.classList.add("is-hidden")}),document.getElementById("anonymous").classList.remove("is-hidden"))}function logout(){localStorage.clear(),update_ui(!1)}function login(){let u,p;q("login","POST",{username:document.getElementById("lu").value,clear_password:document.getElementById("lp").value}).then(response=>{200===response.status&&(update_ui(!0),response.json().then(v=>{localStorage.setItem("token",v)}))},(function(err){}))}function register(){let u,p,p2;q("account","POST",{username:document.getElementById("ru").value,clear_password:document.getElementById("rp").value,clear_password_2:document.getElementById("rpc").value}).then(response=>{},(function(err){}))}async function q(url,method,data){const response=await fetch(url,{method:method,headers:{Accept:"application/json","Content-Type":"application/json"},body:JSON.stringify(data)});return response}window.onload=function(){var token;null!=localStorage.getItem("token")&&update_ui(!0)},document.addEventListener("DOMContentLoaded",()=>{function openModal($el){$el.classList.add("is-active")}function closeModal($el){$el.classList.remove("is-active")}function closeAllModals(){(document.querySelectorAll(".modal")||[]).forEach($modal=>{closeModal($modal)})}(document.querySelectorAll(".js-modal-trigger")||[]).forEach($trigger=>{const modal=$trigger.dataset.target,$target=document.getElementById(modal);$trigger.addEventListener("click",()=>{openModal($target)})}),(document.querySelectorAll(".modal-background, .modal-close, .modal-card-head .delete, .modal-card-foot .button")||[]).forEach($close=>{const $target=$close.closest(".modal");$close.addEventListener("click",()=>{closeModal($target)})}),document.addEventListener("keydown",event=>{const e=event||window.event;"Escape"==e.key&&closeAllModals()})});